; 愚者の倉庫

name = 愚者の倉庫７
insideName = Floor 7
level = 23
bgm = trick
external = n:1
shadow = dark
sky = black
roof = stone
blank = rock
antiWarp = true

; 各パーツ
━ = stone
✜ = stone_h
　 = marble
❖ = marble
☆ = soilr
❑ = cube
／ = door
〆 = key
⧻ = fence
☖ = arch
☗ = gate
︻ = panel
Ⓑ = warp

; 移動ポイント
(A) = map:愚者の倉庫６, x:5, y:0, way:n, symbol:exit, ask:Go to the previous floor?
(B) = map:コリンズの森, x:14, y:66, way:w

; 宝箱
box[1] = 罠はない,スターカード・杯

[map]
